import{_ as i,c as s,a,o as l}from"./app-CEcM0piI.js";const d={};function t(n,e){return l(),s("div",null,e[0]||(e[0]=[a(`<p><code>CMake</code>支持大写、小写、混合大小写的命令。如果在编写<code>CMakeLists.txt</code>文件时使用的工具有对应的命令提示，那么大小写随缘即可，不要太过在意。</p><h2 id="_2-1-注释" tabindex="-1"><a class="header-anchor" href="#_2-1-注释"><span>2.1 注释</span></a></h2><h3 id="_2-1-1-注释行" tabindex="-1"><a class="header-anchor" href="#_2-1-1-注释行"><span>2.1.1 注释行</span></a></h3><p><code>CMake</code> 使用 <code>#</code> 进行<code>行注释</code>，可以放在任何位置。</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span># 这是一个 CMakeLists.txt 文件  </span></span>
<span class="line"><span>cmake_minimum_required(VERSION 3.0.0)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_2-1-2-注释块" tabindex="-1"><a class="header-anchor" href="#_2-1-2-注释块"><span>2.1.2 注释块</span></a></h3><p><code>CMake</code> 使用 <code>#[[ ]]</code> 形式进行<code>块注释</code>。</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>#[[这是一个 CMakeLists.txt 文件。</span></span>
<span class="line"><span>这是一个 CMakeLists.txt 文件。</span></span>
<span class="line"><span>这是一个 CMakeLists.txt 文件。]]</span></span>
<span class="line"><span>cmake_minimum_required(VERSION 3.0.0)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="添加-cmakelists-txt-文件" tabindex="-1"><a class="header-anchor" href="#添加-cmakelists-txt-文件"><span>添加 <code>CMakeLists.txt</code> 文件</span></a></h3><p>在源文件所在目录下添加一个新文件 CMakeLists.txt，文件内容如下：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>cmake_minimum_required(VERSION 3.0)  </span></span>
<span class="line"><span>project(CALC)  </span></span>
<span class="line"><span>add_executable(app add.c div.c main.c mult.c sub.c)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li><p><code>cmake_minimum_required</code>：指定使用的 cmake 的最低版本，必须比本地安装的版本低，<strong>可选，非必须，如果不加可能会有警告</strong>，新的版本会有新的命令，如果使用的命令低版本中不存在则需要把此参数改为支持的版本，本地cmake版本也要在对应版本及以上</p></li><li><p><code>project</code>：定义工程名称，并可指定工程的版本、工程描述、web主页地址、支持的语言（默认情况支持所有语言），如果不需要这些都是可以忽略的，只需要指定出工程名字即可。</p></li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span># PROJECT 指令的语法是：  </span></span>
<span class="line"><span>project(&lt;PROJECT-NAME&gt; [&lt;language-name&gt;...])  </span></span>
<span class="line"><span>project(&lt;PROJECT-NAME&gt;                       #项目的名字</span></span>
<span class="line"><span>       [VERSION &lt;major&gt;[.&lt;minor&gt;[.&lt;patch&gt;[.&lt;tweak&gt;]]]]   #当前项目的版本</span></span>
<span class="line"><span>       [DESCRIPTION &lt;project-description-string&gt;]    #字符串，对当前项目的描述</span></span>
<span class="line"><span>       [HOMEPAGE_URL &lt;url-string&gt;]         #地址，如果项目有自己的网站可以在这里指出</span></span>
<span class="line"><span>       [LANGUAGES &lt;language-name&gt;...])   #项目使用的语言，默认支持所有语言</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li><code>add_executable</code>：定义工程会生成一个可执行程序，只需要添加源文件不需要头文件</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>add_executable(可执行程序名 源文件名称)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>这里的可执行程序名和<code>project</code>中的项目名没有任何关系 源文件名可以是一个也可以是多个，如有多个可用空格或<code>;</code>间隔</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span># 样式1  </span></span>
<span class="line"><span>add_executable(app add.c div.c main.c mult.c sub.c)  </span></span>
<span class="line"><span># 样式2  </span></span>
<span class="line"><span>add_executable(app add.c;div.c;main.c;mult.c;sub.c)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="执行cmake-命令" tabindex="-1"><a class="header-anchor" href="#执行cmake-命令"><span>执行<code>CMake</code> 命令</span></a></h4><p>将 CMakeLists.txt 文件编辑好之后，就可以执行 <code>cmake</code>命令了。</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span># cmake 命令原型  </span></span>
<span class="line"><span>$ cmake CMakeLists.txt文件所在路径</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>当执行<code>cmake</code>命令之后，CMakeLists.txt 中的命令就会被执行，所以一定要注意给<code>cmake</code> 命令指定路径的时候一定不能出错。 执行命令之后，源文件所在目录中多了一些同名的.exe文件 <strong>cmake命令在那个路径运行就在哪个路径生成makefile文件</strong> 且在对应的目录下生成了一个<code>makefile</code>文件，此时再执行<code>make</code>命令，就可以对项目进行构建得到所需的可执行程序了。 最终可执行程序<code>app</code>就被编译出来了（这个名字是在<code>CMakeLists.txt</code>中指定的）。</p><p>如果在<code>CMakeLists.txt</code>文件所在目录执行了<code>cmake</code>命令之后就会生成一些目录和文件（<code>包括 makefile 文件</code>），如果再基于<code>makefile文件</code>执行<code>make</code>命令，程序在编译过程中还会生成一些中间文件和一个可执行文件，这样会导致整个项目目录看起来很混乱，不太容易管理和维护，此时我们就可以把生成的这些与项目源码无关的文件统一放到一个对应的目录里边，比如将这个目录命名为<code>build</code>:</p><p>现在<code>cmake</code>命令是在<code>build</code>目录中执行的，但是<code>CMakeLists.txt</code>文件是<code>build</code>目录的上一级目录中，所以<code>cmake</code> 命令后指定的路径为<code>..</code>，即当前目录的上一级目录。</p><p>当命令执行完毕之后，在<code>build</code>目录中会生成一个<code>makefile</code>文件</p><p>这样就可以在<code>build</code>目录中执行<code>make</code>命令编译项目，生成的相关文件自然也就被存储到<code>build</code>目录中了。这样通过<code>cmake</code>和<code>make</code>生成的所有文件就全部和项目源文件隔离开了</p><h1 id="set的使用" tabindex="-1"><a class="header-anchor" href="#set的使用"><span>set的使用</span></a></h1><h2 id="定义变量" tabindex="-1"><a class="header-anchor" href="#定义变量"><span>定义变量</span></a></h2><p>如果项目的源文件过多全写到add_executable()中也难以维护，可以使用变量接受这些源文件名，在cmake中式可以定义变量的</p><p>在set命令中输入变量值的时候变量值都是字符串类型，即使输入整形也还是字符串需要经过转换</p><p>语法：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>SET(VAR [VALUE] [CACHE TYPE DOCSTRING [FORCE]])</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>[] 中的参数为可选项, 如不需要可以不写</p><ul><li><code>VAR</code>：变量名</li><li><code>VALUE</code>：变量值</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span># 各个源文件之间使用空格间隔也可以使用分号;间隔 </span></span>
<span class="line"><span># set(SRC_LIST add.c div.c main.c mult.c sub.c)  </span></span>
<span class="line"><span>  </span></span>
<span class="line"><span>add_executable(app  \${SRC_LIST})</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>对变量取值使用<code>\${变量名}</code>，否则直接使用变量名只是把变量名变成一个字符串</p><h2 id="指定使用的c-标准" tabindex="-1"><a class="header-anchor" href="#指定使用的c-标准"><span>指定使用的C++标准</span></a></h2><p>直接使用指令使用对应标准编译的命令：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>$ g++ *.cpp -std=c++11 -o app</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>在CMake中想要指定C++标准有两种方式：</p><ol><li>在 CMakeLists.txt 中通过 set 命令指定，如：</li></ol><div class="language-增加-std=c++11 line-numbers-mode" data-highlighter="shiki" data-ext="增加-std=c++11" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>set(CMAKE_CXX_STANDARD 11)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ol start="2"><li>在执行 cmake 命令的时候指定出这个宏的值</li></ol><div class="language-增加-std=c++11 line-numbers-mode" data-highlighter="shiki" data-ext="增加-std=c++11" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>cmake CMakeLists.txt文件路径 -DCMAKE_CXX_STANDARD=11</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>-D表示指出一个宏</p><h2 id="指定输出路径" tabindex="-1"><a class="header-anchor" href="#指定输出路径"><span>指定输出路径</span></a></h2><p>在CMake中指定可执行程序输出的路径，也对应一个宏，叫做<code>EXECUTABLE_OUTPUT_PATH</code>，它的值还是通过<code>set</code>命令进行设置:</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>set(HOME /home/robin/Linux/Sort)  #定义一个变量用于存储一个绝对路径</span></span>
<span class="line"><span>set(EXECUTABLE_OUTPUT_PATH \${HOME}/bin)  #将拼接好的路径值设置给EXECUTABLE_OUTPUT_PATH宏</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>如果路径中的子目录不存在，会自动生成 由于可执行程序是基于 cmake 命令生成的 makefile 文件然后再执行 make 命令得到的，所以如果此处指定可执行程序生成路径的时候使用的是相对路径 ./xxx/xxx，那么这个路径中的 ./ 对应的就是 makefile 文件所在的那个目录。</p><p>在指定目录的前面的路径中不能存在makefile文件，否则就不会生成文件了</p><h1 id="搜索" tabindex="-1"><a class="header-anchor" href="#搜索"><span>搜索</span></a></h1><p>当文件过多时使用set指定变量再传入add_executable中也不好维护，在CMake中为我们提供了搜索文件的命令，可以使用<code>aux_source_directory</code>命令或者<code>file</code>命令。</p><ol><li>使用<code>aux_source_directory</code> 命令可以查找某个路径下的所有源文件：</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>aux_source_directory(&lt; dir &gt; &lt; variable &gt;)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ul><li><code>dir</code>：要搜索的目录</li><li><code>variable</code>：将从<code>dir</code>目录下搜索到的源文件列表存储到该变量中</li></ul><p><strong>PROJECT_SOURCE_DIR宏</strong> 在执行cmake命令时所在路径后边携带的路径（通常是CMakeLists.text所在的路径） 查找执行cmake命令的所在路径中的文件</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>aux_source_directory(\${PROJECT_SOURCE_DIR} SRC)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>CMAKE_CURRENT_SOURCE_DIR宏</strong> CMakeLists.txt所在的路径 通常是和PROJECT_SOURCE_DIR但如果CMakeLists.txt嵌套就不一样了</p><ol><li>如果一个项目里边的源文件很多，在编写<code>CMakeLists.txt</code>文件的时候不可能将项目目录的各个文件一一罗列出来，这样太麻烦了。所以，在CMake中为我们提供了搜索文件的命令<code>file</code>（除了搜索以外通过 file 还可以做其他事情）。</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>file(GLOB/GLOB_RECURSE 变量名 要搜索的文件路径和文件类型)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ul><li><code>GLOB</code>: 将指定目录下搜索到的满足条件的所有文件名生成一个列表，并将其存储到变量中。</li><li><code>GLOB_RECURSE</code>：递归搜索指定目录，将搜索到的满足条件的文件名生成一个列表，并将其存储到变量中。 搜索CMakeLists.txt所在目录中所有的.cpp文件</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>file(GLOB SRC \${CMAKE_CURRENT_SOURCE_DIR}/*.cpp)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><blockquote><p>[!warning] Warning aux_source_directory和file指定文件还不一样，aux_source_directory只需要指定出路径就可以自动匹配所有文件包括.c、.cpp、.h，但file不仅需要指定出路径还要指定出文件类型与路径进行拼接，且aux不可以递归文件，file可以递归搜索</p></blockquote><h1 id="包含头文件" tabindex="-1"><a class="header-anchor" href="#包含头文件"><span>包含头文件</span></a></h1><p>在编译项目源文件的时候，很多时候都需要将源文件对应的头文件路径指定出来，这样才能保证在编译过程中编译器能够找到这些头文件，并顺利通过编译。 若在源文件中指定出头文件的路径需要的是头文件相对于源文件的路径，而不是相对于生成.exe的路径 如果改变头文件的路径使用到此头文件的文件中也要跟随着更改包含头文件的路径，这样会不方便 可以在cmake中可以使用<code>include_directories</code>指定出放置头文件的路径</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>include_directories(headpath)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>源文件中依旧可以直接include头文件名而不用指定出路径 指定出头文件所在地址是和CMakeLists.txt同级目录下的include文件夹中：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>include_directories(\${CMAKE_CURRENT_SOURCE_DIR}/include)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h1 id="制作动态库或静态库" tabindex="-1"><a class="header-anchor" href="#制作动态库或静态库"><span>制作动态库或静态库</span></a></h1><ol><li>制作静态库 在cmake中，如果要制作静态库，需要使用的命令如下：</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>add_library(库名称 STATIC 源文件1 [源文件2] ...)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>在Linux中，静态库名字分为三部分：<code>lib</code>+<code>库名字</code>+<code>.a</code>，此处只需要指定出库的名字就可以了，另外两部分在生成该文件的时候会自动填充。 在Windows中，动态库名字分为三部分：<code>lib</code>+<code>库名字</code>+<code>.lib</code></p><ol start="2"><li>制作动态库 动态库是有可执行权限的，静态库没有 动态库也叫共享库，shared是共享的意思 在cmake中，如果要制作动态库，需要使用的命令如下：</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>add_library(库名称 SHARED 源文件1 [源文件2] ...)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>在Linux中，动态库名字分为三部分：<code>lib</code>+<code>库名字</code>+<code>.so</code>，此处只需要指定出库的名字就可以了，另外两部分在生成该文件的时候会自动填充。 在Windows中，动态库名字分为三部分：<code>lib</code>+<code>库名字</code>+<code>.dll</code></p><p>在Windows中虽然库名和Linux格式不同，但也只需指定出名字即可。</p><p><strong>指定输出的路径</strong> 如果不指定目录会自动生成到当前的构建目录里面</p><p>可以通过<code>set</code>命令给<code>EXECUTABLE_OUTPUT_PATH</code>宏设置了一个路径，这个路径就是可执行文件生成的路径。只适用于动态库，因为动态库拥有可执行权限 由于在Linux下生成的静态库默认不具有可执行权限，所以在指定静态库生成的路径的时候就不能使用<code>EXECUTABLE_OUTPUT_PATH</code>宏了，而应该使用<code>LIBRARY_OUTPUT_PATH</code>，这个宏对应静态库文件和动态库文件都适用。</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>set(LIBRARY_OUTPUT_PATH \${PROJECT_SOURCE_DIR}/lib)  </span></span>
<span class="line"><span># 生成动态库  </span></span>
<span class="line"><span>#add_library(calc SHARED \${SRC_LIST})  </span></span>
<span class="line"><span># 生成静态库  </span></span>
<span class="line"><span>add_library(calc STATIC \${SRC_LIST})</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="链接库" tabindex="-1"><a class="header-anchor" href="#链接库"><span>链接库</span></a></h3><p>发布库需要发布两个文件一个是库文件（静态或动态都可），一个是头文件，头文件用来指明库文件中都有哪些API。 制作库就相当于把.cpp文件打包成二进制文件，如果没有头文件是无法得知里面都有哪些方法的</p><ol><li>链接静态库</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>link_libraries(&lt;static lib&gt; [&lt;static lib&gt;...])</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>可链接多个静态库</p><ul><li><strong>参数1</strong>：指定出要链接的静态库的名字 可以是全名 <code>libxxx.a</code> 也可以是掐头（<code>lib</code>）去尾（<code>.a</code>）之后的名字 <code>xxx</code></li><li><strong>参数2-N</strong>：要链接的其它静态库的名字 如果该静态库不是系统提供的（自己制作或者使用第三方提供的静态库）<mark>可能出现静态库找不到的情况</mark>，此时可以将静态库的路径也指定出来： 该宏也用于指定出动态库的路径。要写到链接库名之前</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>link_directories(&lt;lib path&gt;)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><blockquote><p>[!info] Title 如果使用的是静态库，静态库中的数据会被打包到生成的可执行程序中去，如果是动态库就不会打包到里面。动态库是在程序执行的时候调用了动态库中的内容，该动态库才会被加载到内存中</p></blockquote><ol start="2"><li>链接动态库 在<code>cmake</code>中链接动态库的命令如下:</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>target_link_libraries(  </span></span>
<span class="line"><span>    &lt;target&gt;   </span></span>
<span class="line"><span>    &lt;PRIVATE|PUBLIC|INTERFACE&gt; &lt;item&gt;...   </span></span>
<span class="line"><span>    [&lt;PRIVATE|PUBLIC|INTERFACE&gt; &lt;item&gt;...]...)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li><strong>target</strong>：指定要加载动态库的文件的名字 <ul><li>可能是一个源文件</li><li>可能是一个动态库文件</li><li>可能是一个可执行文件</li></ul></li><li><strong>PRIVATE|PUBLIC|INTERFACE</strong>：动态库的访问权限，默认为<code>PUBLIC</code> 如果各个动态库之间没有依赖关系，无需做任何设置，三者没有没有区别，一般无需指定，使用默认的 PUBLIC 即可。</li></ul><p><code>动态库的链接具有传递性</code>，如果动态库 A 链接了动态库B、C，动态库D链接了动态库A，此时动态库D相当于也链接了动态库B、C，并可以使用动态库B、C中定义的方法。</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>target_link_libraries(A B C)  </span></span>
<span class="line"><span>target_link_libraries(D A)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li><code>PUBLIC</code>：在public后面的库会被Link到前面的target中，并且里面的符号也会被导出，提供给第三方使用。</li><li><code>PRIVATE</code>：在private后面的库仅被link到前面的target中，并且终结掉，第三方不能感知你调了啥库</li><li><code>INTERFACE</code>：在interface后面引入的库不会被链接到前面的target中，只会导出符号。 如果被链接的是public权限，链接的库中就会有这个库的所有的内容，也就是被链接的库中的数据写入到了链接的库中了；这样即使没有被链接的库也可以运行 如果被链接的是privare权限，那么这个库的数据只会被传递一次（传递到前一个链接的库中） 如果被链接的是interface只会把符号写入到链接的库中（链接库只知道这个库有这个方法及这个方法的名字而不知道具体实现）依旧需要调用被链接的库</li></ul><h4 id="链接系统动态库" tabindex="-1"><a class="header-anchor" href="#链接系统动态库"><span>链接系统动态库</span></a></h4><p>动态库的链接和静态库是完全不同的：</p><ul><li>静态库会在生成可执行程序的链接阶段被打包到可执行程序中，所以可执行程序启动，静态库就被加载到内存中了。</li><li>动态库在生成可执行程序的链接阶段<strong>不会</strong>被打包到可执行程序中，当可执行程序被启动并且调用了动态库中的函数的时候，动态库才会被加载到内存</li></ul><p>在程序运行时，需要用到被链接的库时就将该库写入到物理内存中，但因为优化，物理内存中只允许有一个该库，这样另一个程序也要用到这个动态库时就会调用已经在物理内存中的库，多个应用程序共用一个动态库，因此动态库也称为共享库。</p><p>因此，在<code>cmake</code>中指定要链接的动态库的时候，<mark>应该将命令写到生成了可执行文件之后</mark>：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>cmake_minimum_required(VERSION 3.0)  </span></span>
<span class="line"><span>project(TEST)  </span></span>
<span class="line"><span>file(GLOB SRC_LIST \${CMAKE_CURRENT_SOURCE_DIR}/*.cpp)  </span></span>
<span class="line"><span># 添加并指定最终生成的可执行程序名  </span></span>
<span class="line"><span>add_executable(app \${SRC_LIST})  </span></span>
<span class="line"><span># 指定可执行程序要链接的动态库名字  </span></span>
<span class="line"><span>target_link_libraries(app pthread)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>在<code>target_link_libraries(app pthread)</code>中：</p><ul><li><code>app:</code> 对应的是最终生成的可执行程序的名字</li><li><code>pthread</code>：这是可执行程序要加载的动态库，这个库是系统提供的线程库，全名为<code>libpthread.so</code>，在指定的时候一般会掐头（lib）去尾（.so）。</li></ul><p>如果源代码比较多适合生成动态库，源代码比较少适合生成静态库</p><h1 id="日志" tabindex="-1"><a class="header-anchor" href="#日志"><span>日志</span></a></h1><p>用于调试 在CMake中可以用用户显示一条消息，该命令的名字为<code>message</code>：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>message([STATUS|WARNING|AUTHOR_WARNING|FATAL_ERROR|SEND_ERROR] &quot;message to display&quot; ...)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>前面的关键字代表消息的重要级别</p><table><thead><tr><th>关键字</th><th>作用</th></tr></thead><tbody><tr><td>没有关键字</td><td>重要消息</td></tr><tr><td><code>STATUS</code></td><td>非重要消息</td></tr><tr><td><code>WARNING</code></td><td>警告, 会继续执行</td></tr><tr><td><code>AUTHOR_WARNING</code></td><td>重要警告 (dev), 会继续执行</td></tr><tr><td><code>SEND_ERROR</code></td><td>非重要错误, 继续执行，但是会跳过生成的步骤</td></tr><tr><td><code>FATAL_ERROR</code></td><td>重要错误, 终止所有处理过程</td></tr></tbody></table><h1 id="变量操作" tabindex="-1"><a class="header-anchor" href="#变量操作"><span>变量操作</span></a></h1><h2 id="追加" tabindex="-1"><a class="header-anchor" href="#追加"><span>追加</span></a></h2><p>有时候项目中的源文件并不一定都在同一个目录中，但是这些源文件最终却需要一起进行编译来生成最终的可执行文件或者库文件。如果我们通过<code>file</code>命令对各个目录下的源文件进行搜索，最后还需要做一个字符串拼接的操作，关于字符串拼接可以使用<code>set</code>命令也可以使用<code>list</code>命令。</p><h3 id="使用set拼接" tabindex="-1"><a class="header-anchor" href="#使用set拼接"><span>使用set拼接</span></a></h3><p>如果使用set进行字符串拼接，对应的命令格式如下：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>set(变量名1 \${变量名1} \${变量名2} ...)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>将从第二个参数开始往后所有的字符串进行拼接，最后将结果存储到第一个参数中，如果第一个参数中原来有数据会对原数据就行覆盖。</p><h3 id="使用list拼接" tabindex="-1"><a class="header-anchor" href="#使用list拼接"><span>使用list拼接</span></a></h3><p>如果使用list进行字符串拼接，对应的命令格式如下：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>list(APPEND &lt;list&gt; [&lt;element&gt; ...])</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><code>list</code>命令的功能比<code>set</code>要强大，字符串拼接只是它的其中一个功能，所以需要在它第一个参数的位置指定出我们要做的操作，<code>APPEND</code>表示进行数据追加，后边的参数和<code>set</code>就一样了。 cmake中并没有list，&lt;list&gt;是一个字符串，后面的参数是拼接后添加到&lt;list&gt;中 &lt;list&gt;虽然对应的是一个变量，但是cmake在底层管理的时候会把若干个子字符串通过分号间隔，但是通过message进行输出是没有分号的。这是因为list虽然能完成字符串的拼接还能完成字符串的删除，删除的是存储到&lt;list&gt;里面的某个字符串，在删除时就会进行搜索，如果没有分号搜索时就会有问题。</p><h2 id="字符串移除" tabindex="-1"><a class="header-anchor" href="#字符串移除"><span>字符串移除</span></a></h2><p>我们在通过<code>file</code>搜索某个目录就得到了该目录下所有的源文件，但是其中有些源文件并不是我们所需要的。此时，就需要将不需要的文件从搜索到的数据中剔除出去，想要实现这个功能，也可以使用<code>list</code></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>list(REMOVE_ITEM &lt;list&gt; &lt;value&gt; [&lt;value&gt; ...])</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>后边的&lt;value&gt;就是要删除的字符串，可以删除多个</p><h3 id="list的其他作用" tabindex="-1"><a class="header-anchor" href="#list的其他作用"><span>list的其他作用</span></a></h3><ol><li>获取 list 的长度（字符串个数）。</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>list(LENGTH &lt;list&gt; &lt;output variable&gt;)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ul><li><code>LENGTH</code>：子命令LENGTH用于读取列表长度</li><li><code>&lt;list&gt;</code>：当前操作的列表</li><li><code>&lt;output variable&gt;</code>：新创建的变量，用于存储列表的长度。（写入的虽然是数字但依旧是字符串类型）</li></ul><ol start="2"><li>读取列表中指定索引的的元素，可以指定多个索引</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>list(GET &lt;list&gt; &lt;element index&gt; [&lt;element index&gt; ...] &lt;output variable&gt;)|</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ul><li><code>&lt;list&gt;</code>：当前操作的列表</li><li><code>&lt;element index&gt;</code>：列表元素的索引 <ul><li>从0开始编号，索引0的元素为列表中的第一个元素；</li><li>索引也可以是负数，<code>-1</code>表示列表的最后一个元素，<code>-2</code>表示列表倒数第二个元素，以此类推</li><li>当索引（不管是正还是负）超过列表的长度，运行会报错</li></ul></li><li><code>&lt;output variable&gt;</code>：新创建的变量，存储指定索引元素的返回结果，也是一个列表。</li></ul><ol start="3"><li>将列表中的元素用连接符（字符串）连接起来组成一个字符串</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>list (JOIN &lt;list&gt; &lt;glue&gt; &lt;output variable&gt;)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ul><li><code>&lt;list&gt;</code>：当前操作的列表</li><li><code>&lt;glue&gt;</code>：指定的连接符（字符串）</li><li><code>&lt;output variable&gt;</code>：新创建的变量，存储返回的字符串</li></ul><ol start="4"><li>查找列表是否存在指定的元素，若果未找到，返回-1</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>list(FIND &lt;list&gt; &lt;value&gt; &lt;output variable&gt;)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ol><li><ul><li><code>&lt;list&gt;</code>：当前操作的列表</li><li><code>&lt;value&gt;</code>：需要再列表中搜索的元素</li><li><code>&lt;output variable&gt;</code>：新创建的变量 <ul><li>如果列表<code>&lt;list&gt;</code>中存在<code>&lt;value&gt;</code>，那么返回<code>&lt;value&gt;</code>在列表中的索引</li><li>如果未找到则返回-1。</li></ul></li></ul></li><li><p>将元素追加到列表中</p></li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>list (APPEND &lt;list&gt; [&lt;element&gt; ...])</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ol start="6"><li>在list中指定的位置插入若干元素 索引从0开始</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>list(INSERT &lt;list&gt; &lt;element_index&gt; &lt;element&gt; [&lt;element&gt; ...])</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ol start="7"><li>将元素插入到列表的0索引位置</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>list (PREPEND &lt;list&gt; [&lt;element&gt; ...])</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ol start="8"><li>将列表中最后元素移除</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>list (POP_BACK &lt;list&gt; [&lt;out-var&gt;...])</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ol start="9"><li>将列表中第一个元素移除</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>list (POP_FRONT &lt;list&gt; [&lt;out-var&gt;...])</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ol start="10"><li>将指定的元素从列表中移除</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>list (REMOVE_ITEM &lt;list&gt; &lt;value&gt; [&lt;value&gt; ...])</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ol start="11"><li>将指定索引的元素从列表中移除</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>list (REMOVE_AT &lt;list&gt; &lt;index&gt; [&lt;index&gt; ...])</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ol start="12"><li>移除列表中的重复元素</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>list (REMOVE_DUPLICATES &lt;list&gt;)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ol start="13"><li>列表翻转</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>list(REVERSE &lt;list&gt;)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ol start="14"><li>列表排序</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>list (SORT &lt;list&gt; [COMPARE &lt;compare&gt;] [CASE &lt;case&gt;] [ORDER &lt;order&gt;])</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ul><li><code>COMPARE</code>：指定排序方法。有如下几种值可选： <ul><li><code>STRING</code>:按照字母顺序进行排序，为默认的排序方法</li><li><code>FILE_BASENAME</code>：如果是一系列路径名，会使用basename进行排序</li><li><code>NATURAL</code>：使用自然数顺序排序</li></ul></li><li><code>CASE</code>：指明是否大小写敏感。有如下几种值可选： <ul><li><code>SENSITIVE</code>: 按照大小写敏感的方式进行排序，为默认值</li><li><code>INSENSITIVE</code>：按照大小写不敏感方式进行排序</li></ul></li><li><code>ORDER</code>：指明排序的顺序。有如下几种值可选： <ul><li><code>ASCENDING</code>:按照升序排列，为默认值</li><li><code>DESCENDING</code>：按照降序排列</li></ul></li></ul><h1 id="宏定义" tabindex="-1"><a class="header-anchor" href="#宏定义"><span>宏定义</span></a></h1><p>在进行程序测试的时候，我们可以在代码中添加一些宏定义，通过这些宏来控制这些代码是否生效</p><div class="language- line-numbers-mode has-collapsed-lines collapsed" data-highlighter="shiki" data-ext="" style="--vp-collapsed-lines:15;--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>#include &lt;stdio.h&gt;  </span></span>
<span class="line"><span>#define NUMBER  3  </span></span>
<span class="line"><span>  </span></span>
<span class="line"><span>int main()  </span></span>
<span class="line"><span>{  </span></span>
<span class="line"><span>    int a = 10;  </span></span>
<span class="line"><span>#ifdef DEBUG  </span></span>
<span class="line"><span>    printf(&quot;我是一个程序猿, 我不会爬树...\\n&quot;);  </span></span>
<span class="line"><span>#endif  </span></span>
<span class="line"><span>    for(int i=0; i&lt;NUMBER; ++i)  </span></span>
<span class="line"><span>    {  </span></span>
<span class="line"><span>        printf(&quot;hello, GCC!!!\\n&quot;);  </span></span>
<span class="line"><span>    }  </span></span>
<span class="line"><span>    return 0;  </span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div><div class="collapsed-lines"></div></div><p>在程序的第七行对<code>DEBUG</code>宏进行了判断，如果该宏被定义了，那么第八行就会进行日志输出，如果没有定义这个宏，第八行就相当于被注释掉了，因此最终无法看到日志输入出（<strong>上述代码中并没有定义这个宏</strong>）。</p><p>为了让测试更灵活，我们可以不在代码中定义这个宏，而是在测试的时候去把它定义出来，其中一种方式就是在<code>gcc/g++</code>命令中去指定，如下：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>$ gcc test.c -DDEBUG -o app</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>在<code>gcc/g++</code>命令中通过参数 <code>-D</code>指定出要定义的宏的名字，这样就相当于在代码中定义了一个宏，其名字为<code>DEBUG</code>。 在<code>CMake</code>中我们也可以做类似的事情，对应的命令叫做<code>add_definitions</code>:</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>add_definitions(-D宏名称)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>如：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span># 自定义 DEBUG 宏  </span></span>
<span class="line"><span>add_definitions(-DDEBUG)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>通过这种方式，上述代码中的第八行日志就能够被输出出来了。</p><h2 id="预定义宏" tabindex="-1"><a class="header-anchor" href="#预定义宏"><span>预定义宏</span></a></h2><p>cmake中预定义的宏</p><table><thead><tr><th style="text-align:center;">宏</th><th style="text-align:center;">功能</th></tr></thead><tbody><tr><td style="text-align:center;">PROJECT_SOURCE_DIR</td><td style="text-align:center;">使用cmake命令后紧跟的目录，一般是工程的根目录</td></tr><tr><td style="text-align:center;">PROJECT_BINARY_DIR</td><td style="text-align:center;">执行cmake命令的目录</td></tr><tr><td style="text-align:center;">CMAKE_CURRENT_SOURCE_DIR</td><td style="text-align:center;">当前处理的CMakeLists.txt所在的路径</td></tr><tr><td style="text-align:center;">CMAKE_CURRENT_BINARY_DIR</td><td style="text-align:center;">target 编译目录</td></tr><tr><td style="text-align:center;">EXECUTABLE_OUTPUT_PATH</td><td style="text-align:center;">重新定义目标二进制可执行文件的存放位置</td></tr><tr><td style="text-align:center;">LIBRARY_OUTPUT_PATH</td><td style="text-align:center;">重新定义目标链接库文件的存放位置</td></tr><tr><td style="text-align:center;">PROJECT_NAME</td><td style="text-align:center;">返回通过PROJECT指令定义的项目名称</td></tr><tr><td style="text-align:center;">CMAKE_BINARY_DIR</td><td style="text-align:center;">项目实际构建路径，假设在<code>build</code>目录进行的构建，那么得到的就是这个目录的路径</td></tr></tbody></table><h2 id="find-package" tabindex="-1"><a class="header-anchor" href="#find-package"><span>find_package</span></a></h2><p>find_package主要用于导入包时找到包路径,找包规则是包制作者提供的,我们只需给出找包规则的路径即可 不同的包查找路径的宏定义也不同,以qt为例在qt6中要制定的搜索规则是Qt6_DIR</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>set(Qt6_DIR &quot;D:\\\\Develop\\\\Qt\\\\6.8.1\\\\mingw_64\\\\lib\\\\cmake\\\\Qt6&quot;)</span></span>
<span class="line"><span>find_package(Qt6 COMPONENTS Widgets REQUIRED)</span></span>
<span class="line"><span>target_link_libraries(\${PROJECT_NAME} Qt6::Widgets)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>`,171)]))}const r=i(d,[["render",t]]),h=JSON.parse('{"path":"/cpp/cmake/2/","title":"2 CMake的使用","lang":"zh-CN","frontmatter":{"title":"2 CMake的使用","createTime":"2025/04/05 12:12:26","permalink":"/cpp/cmake/2/"},"readingTime":{"minutes":19.54,"words":5863},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/C++/cmake/2 CMake的使用.md","headers":[]}');export{r as comp,h as data};
